/**
 * Serves a file from Google Cloud Storage based on HTTP request query parameters.
 *
 * Expects 'bucket' and 'path' query parameters in the request URL.
 * Example URL: /serveFile?bucket=your-bucket-name&path=folder/subfolder/your-file.txt
 *
 * @param {object} req The HTTP request object.
 * @param {object} res The HTTP response object.
 */
exports.serveFile = async (req, res) => {
  const bucketName = req.query.bucket;
  const filePath = req.query.path;

  if (!bucketName || !filePath) {
    res.status(400).send('Missing "bucket" or "path" query parameter. Please provide both.');
    return;
  }

  const file = storage.bucket(bucketName).file(filePath);

  try {
    // Check if the file exists in the specified bucket and path
    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send(`File not found: gs://${bucketName}/${filePath}`);
      return;
    }

    // Get file metadata to determine Content-Type for the HTTP response
    const [metadata] = await file.getMetadata();
    const contentType = metadata.contentType || 'application/octet-stream'; // Default to binary if not found

    // Set the Content-Type header
    res.setHeader('Content-Type', contentType);
    // Optionally, set Content-Disposition for download behavior
    // res.setHeader('Content-Disposition', `attachment; filename="${file.name.split('/').pop()}"`);

    // Create a readable stream from the Cloud Storage file and pipe it directly to the HTTP response
    file.createReadStream()
      .on('error', (err) => {
        console.error(`Error streaming file gs://${bucketName}/${filePath}:`, err);
        if (!res.headersSent) {
          // If headers haven't been sent, we can still send a 500 error.
          res.status(500).send('Error streaming file.');
        } else {
          // If headers were sent, the client might already be receiving partial content.
          // Just end the response to prevent hanging.
          res.end();
        }
      })
      .pipe(res); // Pipe the file stream directly to the response stream

  } catch (err) {
    console.error(`Error accessing Cloud Storage for gs://${bucketName}/${filePath}:`, err);

    // Handle common Cloud Storage errors
    if (err.code === 403) {
      res.status(403).send('Permission denied. Ensure the Cloud Function service account has Storage Object Viewer role for the bucket.');
    } else if (err.code === 404) {
      // This case should ideally be caught by file.exists() but serves as a fallback
      res.status(404).send(`Bucket or file not found: gs://${bucketName}/${filePath}`);
    } else {
      res.status(500).send('An unexpected error occurred while accessing Cloud Storage.');
    }
  }
};